let webhookData = [];
try {
  // 尝试获取 When Executed by Another Workflow 节点的数据
  webhookData = $("When Executed by Another Workflow").all();
} catch(e) {
  // 如果没这个节点，报错则用 Webhook 节点数据
  webhookData = [];
}

if (!webhookData || webhookData.length === 0) {
  try {
    webhookData = $("Webhook").all();
  } catch(e) {
    webhookData = [];
  }
}

const procedureNameFromWebhook = webhookData?.[0]?.json?.body?.procedure_name;

// 从 input 获取所有过程数据
const inputData = $input.all();

// 从 Edit Fields 节点获取 retroid_id 数据
let editFieldsData = [];
try {
  editFieldsData = $("Edit Fields").all();
} catch (e) {
  editFieldsData = [];
}
const retroidId = editFieldsData.length > 0 ? editFieldsData[0].json.retroid_id : null;

// 查找当前工序的数据
const currentProcedureIndex = inputData.findIndex(item => item.json.procedure_name === procedureNameFromWebhook);

if (currentProcedureIndex !== -1) {
  const currentProcedure = inputData[currentProcedureIndex].json;
  const previousProcedure = currentProcedureIndex > 0 ? inputData[currentProcedureIndex - 1].json : null;

  return [
    {
      json: {
        currentProcedure: {
          procedure_name: currentProcedure.procedure_name,
          history_procedure_id: currentProcedure.history_procedure_id,
          procedure_detail_id: currentProcedure.procedure_detail_id,
          checkrule:currentProcedure.checkrule,
        },
        previousProcedure: previousProcedure ? {
          procedure_name: previousProcedure.procedure_name,
          history_procedure_id: previousProcedure.history_procedure_id,
          procedure_detail_id: previousProcedure.procedure_detail_id,
        } : null,
        retroidId: retroidId
      }
    }
  ];
} else {
  // 没找到匹配时也要 return array，避免 n8n 报错
  return [];
}

// 1. 【修改点1】获取所有入参中的 skip_procedure_id 并存为数组
const inputItems = $input.all();

// 使用 map 提取所有项的 skip_procedure_id，并确保转换为字符串。同时过滤掉空值。
// 结果类似: ["95", "149", "148"]
const skipProcedureIdsToDelete = inputItems
    .map(item => (item.json.skip_procedure_id ? String(item.json.skip_procedure_id) : null))
    .filter(id => id !== null); // 过滤掉没有该字段的项造成的null

// 2. 获取其他节点的数据 (保持不变)
const datas = $("查询对应工序表").all();

// 判空保护：如果工序表没查到数据
if (!datas || datas.length === 0) {
  return [];
}

// 获取上下文节点 (保持不变)
const contextNode = $('校验当前工序是否需要校验所有前置工序').first();

// 判空保护：如果上游节点没数据
if (!contextNode || !contextNode.json) {
  return [];
}

const retroidId = contextNode.json.retroidId;
const currentProcedure = contextNode.json.currentProcedure;

if (!currentProcedure) {
  return [];
}

// 3. 找到当前工序对象 (保持不变)
const currentItem = datas.find(
  item => 
    item.json.procedure_name === currentProcedure.procedure_name && 
    item.json.procedure_detail_id === currentProcedure.procedure_detail_id
);

if (!currentItem) {
  return [];
}

const currentSortOrder = currentItem.json.sort_order;

// 4. 过滤逻辑
const result = datas.filter(item => {
  // a. 必须是前置工序 (sort_order 小于当前) (保持不变)
  if (item.json.sort_order >= currentSortOrder) return false;

  // b. 排除特定名称的工序 (保持不变)
  const excludedNames = [
    "FPC ID与MIC ID绑定",
    "LCD与TP绑定",
    "PPG点胶-保压起始"
  ];
  if (excludedNames.includes(item.json.procedure_name)) return false;

  // c. 【修改点2】剔除 在 skipProcedureIdsToDelete 数组中的工序
  // 使用数组的 .includes 方法来判断当前工序ID是否在要删除的列表中
  if (skipProcedureIdsToDelete.length > 0) {
      const currentDetailIdStr = String(item.json.procedure_detail_id);
      if (skipProcedureIdsToDelete.includes(currentDetailIdStr)) {
         return false; 
      }
  }

  return true;
});

// 结果处理 (保持不变)
const procedure_detail_ids = result
  .map(item => item.json.procedure_detail_id)
  .join(',');

return [
  {
    json: {
      procedure_detail_ids,
      retroidId
    }
  }
];

const arr = $input.all().map(item => ({
  procedure_detail_id: item.json.procedure_detail_id,
  machine_data_id: item.json.machine_data_id,
  retroid_id: item.json.retroid_id
}));
return [{ json: { items: arr } }];

// 1. 获取所有工序节点数据
const allProcedureNodes = $('查询对应工序表').all();

// 2. 要排除的工序名称
const excludeNames = [
  'FPC ID与MIC ID绑定',
  'LCD与TP绑定',
  'PPG点胶-保压起始'
];

// 3. 找到要排除的procedure_detail_id们
const excludeIdsSet = new Set(
  allProcedureNodes
    .filter(node => excludeNames.includes(node.json.procedure_name))
    .map(node => Number(node.json.procedure_detail_id))
);

// 4. 获取并过滤needIds
const needIdsStr = $('整合查询数据').first().json.procedure_detail_ids || '';
const needIds = needIdsStr
  .split(',')
  .map(id => Number(id))
  .filter(id => !isNaN(id) && !excludeIdsSet.has(id));

// ====== 核心修改区域 Start ======

// A. 获取“物理上做过”的记录 (历史记录)
const finishedItems = $('查询所有前置工序是否完成').all();
const finishedIds = new Set(finishedItems.map(item => Number(item.json.procedure_detail_id)));

// B. 获取“发生过解绑”的记录 (作废记录)
const unbindItems = $('确认所有数据没有解绑').all();
const unboundIds = new Set(unbindItems.map(item => {
    const json = item.json;

    // 【修复点】：根据你的JSON结构，old_id在data对象下，与data_old平级
    // 路径尝试1：如果字段在根目录（SQL直接查出）
    if (json.procedure_detail_id_old) {
        return Number(json.procedure_detail_id_old);
    }

    // 路径尝试2：字段在 data 对象里
    if (json.data && json.data.procedure_detail_id_old) {
        return Number(json.data.procedure_detail_id_old);
    }

    return 0; // 没找到则返回0，不影响逻辑
}));

// ====== 核心修改区域 End ======

const lackIds = [];

for (const id of needIds) {
  // 判定逻辑：
  // 1. 历史记录里有 (finishedIds) 
  // 2. 且不能在解绑名单里 (unboundIds)

  const hasHistory = finishedIds.has(id);
  const isUnbound = unboundIds.has(id); 

  // 如果没做过，或者做过但被解绑了，都算未完成
  if (!hasHistory || isUnbound) {
    lackIds.push(id);
  }
}

if (lackIds.length === 0) {
  return [{
    status: '0'
  }];
} else {
  return [{
    status: '1',
    lack_procedure_detail_ids: lackIds
  }];
}

